144→pub async fn post_toggle_todo(
145→    AuthenticatedUser(user_id): AuthenticatedUser,
146→    State(pool): State<PgPool>,
147→    headers: HeaderMap,
148→    Path(todo_id): Path<Uuid>,
149→) -> Result<Response, TodosError> {
150→    let htmx = is_htmx_request(&headers);
151→    let todo_item_id = TodoItemId::from_uuid(todo_id);
152→
153→    match toggle_todo_completion(&pool, &todo_item_id, &user_id).await {
154→        Ok(toggled) => {
155→            if htmx {
156→                let announce = if toggled.is_completed() {
157→                    "Todo completed"
158→                } else {
159→                    "Todo marked pending"
160→                };
161→                let template = TodoItemTemplate {
162→                    todo: TodoItemView::from(&toggled),
163→                };
164→                let body = template.render().map_err(TodosError::Render)?;
165→                Ok(htmx_response_with_announce(Html(body), announce))
166→            } else {
167→                Ok(Redirect::to("/todos").into_response())
168→            }
169→        }
170→        Err(ToggleTodoError::NotFound) => Ok((
171→            StatusCode::NOT_FOUND,
172→            Html("<h1>Todo not found</h1>".to_string()),
173→        )
174→            .into_response()),
175→        Err(ToggleTodoError::Unauthorized) => Ok((
176→            StatusCode::FORBIDDEN,
177→            Html("<h1>Not authorized</h1>".to_string()),
178→        )
179→            .into_response()),
180→        Err(ToggleTodoError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
181→    }
182→}
